// Pseudocode: publish flow (node-style)
const shard = shardForChannel(channelId);
// Edge proxy forwards client message to shard
await shard.appendToLog(message); // async, durable append
shard.broadcastBatch(message); // in-memory broadcast to edge proxies

// Broadcast loop (simplified)
function broadcastBatch(msg) {
  batchQueue.push(msg);
  if (!broadcastTimer) {
    broadcastTimer = setTimeout(() => {
      const batch = batchQueue.splice(0);
      const framed = encodeBatch(batch); // binary frame + delta encoding
      for (const conn of connections) {
        if (conn.canSend()) conn.socket.send(framed);
        else conn.markSlow(); // coalesce/drop later
      }
      broadcastTimer = null;
    }, BATCH_WINDOW_MS);
  }
}
